-- Create "todos" table
CREATE TABLE "todos" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "text" text NOT NULL, "created_at" timestamptz NOT NULL, "status" character varying NOT NULL DEFAULT 'IN_PROGRESS', "priority" bigint NOT NULL DEFAULT 0, "todo_parent" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "todos_todos_parent" FOREIGN KEY ("todo_parent") REFERENCES "todos" ("id") ON UPDATE NO ACTION ON DELETE SET NULL);
